        document.mime_type = ColumnText(statement.get(), 9);
        document.imported_at = ColumnText(statement.get(), 10);
        document.last_indexed_at = ColumnText(statement.get(), 11);
        document.metadata_json = ColumnText(statement.get(), 12);
